const SHELL_CACHE="dunamis-shell-v4-0-2",SHELL_ASSETS=["./","./index.html","./main.css","./app.js","./config.js","./core/data-layer.js","./manifest.webmanifest"];self.addEventListener("install",e=>{e.waitUntil(caches.open(SHELL_CACHE).then(s=>s.addAll(SHELL_ASSETS))),self.skipWaiting()}),self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(s=>Promise.all(s.filter(n=>n!==SHELL_CACHE).map(n=>caches.delete(n))))),self.clients.claim()}),self.addEventListener("fetch",e=>{if(e.request.method!=="GET")return;const s=new URL(e.request.url);if(!(s.origin===self.location.origin))return;if(["/index.html","/app.js","/config.js","/main.css"].some(t=>s.pathname.endsWith(t))){e.respondWith(fetch(e.request).then(t=>{const c=t.clone();return caches.open(SHELL_CACHE).then(i=>i.put(e.request,c)),t}).catch(()=>caches.match(e.request).then(t=>t||caches.match("./index.html"))));return}e.respondWith(caches.match(e.request).then(t=>t||fetch(e.request).then(c=>{const i=c.clone();return caches.open(SHELL_CACHE).then(a=>a.put(e.request,i)),c}).catch(()=>caches.match("./index.html"))))});
